:root {
  --bg: radial-gradient(circle at 20% 20%, #d7f7ff 0%, #eefcff 40%, #f9f7f3 100%);
  --text: #1f2d3d;
  --card: #ffffffd9;
  --line: #7cb3c7;
  --button: #1f6b83;
  --button-text: #f8fbff;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: var(--bg);
  color: var(--text);
  font-family: "Avenir Next", "Hiragino Kaku Gothic ProN", sans-serif;
}

.page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 24px;
}

.card {
  width: min(560px, 100%);
  border: 2px solid var(--line);
  border-radius: 16px;
  background: var(--card);
  padding: 32px;
  box-shadow: 0 16px 32px rgba(29, 78, 100, 0.15);
}

.card h1 {
  margin-top: 0;
  margin-bottom: 12px;
  font-size: 2rem;
}

.card p {
  margin-top: 0;
  margin-bottom: 24px;
}

.google-button {
  border: none;
  border-radius: 10px;
  padding: 12px 18px;
  background: var(--button);
  color: var(--button-text);
  font-size: 1rem;
  cursor: pointer;
}

.google-button:hover {
  filter: brightness(1.05);
}

.google-button:disabled {
  opacity: 0.7;
  cursor: wait;
}

.error-text {
  color: #b00020;
  margin-top: 12px;
  margin-bottom: 0;
}

.link-button {
  display: inline-block;
  margin-top: 12px;
  padding: 10px 14px;
  background: #f0f7fa;
  border-radius: 8px;
  border: 1px solid #7cb3c7;
  color: #17485a;
  text-decoration: none;
}

.form-block {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.form-block input {
  border: 1px solid #7cb3c7;
  border-radius: 8px;
  padding: 10px 12px;
  font-size: 1rem;
}

.form-block textarea,
.form-block select {
  border: 1px solid #7cb3c7;
  border-radius: 8px;
  padding: 10px 12px;
  font-size: 1rem;
  font-family: inherit;
}

.button-row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.outline-button {
  border: 1px solid #7cb3c7;
  border-radius: 10px;
  padding: 10px 16px;
  background: #ffffff;
  color: #1f2d3d;
  text-decoration: none;
  cursor: pointer;
}

.list {
  margin: 0;
  padding-left: 20px;
}

.list-item {
  margin-bottom: 10px;
}

import type { Metadata } from "next";
import "./styles.css";

export const metadata: Metadata = {
  title: "Memo App",
  description: "Google login based memo app"
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="ja">
      <body>{children}</body>
    </html>
  );
}

