"use client";

import { FormEvent, useEffect, useMemo, useState } from "react";

const apiBaseUrl = process.env.NEXT_PUBLIC_API_BASE_URL ?? "http://localhost:8080";

type Memo = {
  memo_id: string;
  title: string;
  content: string;
  category_id?: string;
  category_name: string;
  created_at: string;
  updated_at: string;
};

type MemoListResponse = {
  memos: Memo[];
};

const formatDateTime = (value: string) => {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit"
  }).format(date);
};

export default function MemoListPage() {
  const [keywordInput, setKeywordInput] = useState("");
  const [keyword, setKeyword] = useState("");
  const [memos, setMemos] = useState<Memo[]>([]);
  const [errorMessage, setErrorMessage] = useState("");

  const queryString = useMemo(() => {
    const params = new URLSearchParams();
    if (keyword.trim()) {
      params.set("keyword", keyword.trim());
    }
    const raw = params.toString();
    return raw ? `?${raw}` : "";
  }, [keyword]);

  useEffect(() => {
    const load = async () => {
      try {
        const response = await fetch(`${apiBaseUrl}/api/memos${queryString}`, {
          credentials: "include"
        });
        if (!response.ok) {
          let message = "メモ一覧の取得に失敗しました";
          try {
            const payload = (await response.json()) as { message?: string };
            message = payload.message ?? message;
          } catch {
            // no-op: use fallback message
          }
          throw new Error(message);
        }
        const payload = (await response.json()) as MemoListResponse;
        setMemos(payload.memos);
        setErrorMessage("");
      } catch (error) {
        setErrorMessage(error instanceof Error ? error.message : "通信に失敗しました");
        setMemos([]);
      }
    };
    void load();
  }, [queryString]);

  const onSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setKeyword(keywordInput);
  };

  return (
    <main className="page">
      <section className="card memo-list-card">
        <header className="memo-list-header">
          <h1>メモ一覧</h1>
          <div className="button-row">
            <a href="/memos/new" className="link-button">
              新規作成
            </a>
            <a href="/categories" className="outline-button">
              カテゴリ管理
            </a>
          </div>
        </header>

        <form onSubmit={onSubmit} className="form-block">
          <input
            type="text"
            value={keywordInput}
            onChange={(event) => setKeywordInput(event.target.value)}
            placeholder="タイトル・本文を検索"
            aria-label="タイトル・本文を検索"
          />
          <button type="submit" className="google-button search-button">
            検索
          </button>
        </form>

        {errorMessage && <p className="error-text list-status">{errorMessage}</p>}
        {!errorMessage && memos.length === 0 && (
          <p className="list-status">該当するメモがありません</p>
        )}

        {!errorMessage && memos.length > 0 && (
          <ul className="memo-list">
            {memos.map((memo) => (
              <li key={memo.memo_id} className="memo-list-item">
                <div className="memo-list-item-header">
                  <a href={`/memos/${memo.memo_id}`} className="memo-title-link">
                    {memo.title}
                  </a>
                  <div className="button-row memo-actions">
                    <a href={`/memos/${memo.memo_id}`} className="link-button">
                      詳細
                    </a>
                    <a href={`/memos/${memo.memo_id}/edit`} className="outline-button">
                      編集
                    </a>
                    <a href={`/memos/${memo.memo_id}/delete`} className="danger-link">
                      削除
                    </a>
                  </div>
                </div>

                <p className="memo-content-preview">{memo.content.trim() || "本文なし"}</p>

                <div className="memo-meta">
                  <span className="memo-category">{memo.category_name || "未分類"}</span>
                  <span>作成: {formatDateTime(memo.created_at)}</span>
                  <span>更新: {formatDateTime(memo.updated_at)}</span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}

