use crate::auth::session;
use crate::db::user_repository;
use crate::errors::api_error::ApiError;
use crate::AppState;
use axum::{extract::Query, extract::State, Json};
use axum_extra::extract::cookie::CookieJar;
use serde::{Deserialize, Serialize};
use std::env;

#[derive(Serialize)]
pub struct MessageResponse {
    pub message: &'static str,
}

#[derive(Serialize)]
pub struct LoginStartResponse {
    pub message: &'static str,
    pub auth_url: &'static str,
}

#[derive(Serialize)]
pub struct MeResponse {
    pub user_id: String,
    pub google_sub: String,
    pub user_name: String,
    pub email: String,
}

#[derive(serde::Deserialize)]
pub struct GoogleCallbackQuery {
    pub google_sub: String,
    pub user_name: String,
    pub email: String,
}

#[derive(Deserialize)]
pub struct GoogleVerifyRequest {
    pub id_token: String,
}

#[derive(Deserialize)]
struct GoogleTokenInfoResponse {
    aud: Option<String>,
    sub: Option<String>,
    email: Option<String>,
    name: Option<String>,
}

pub async fn start_google_login() -> Result<Json<LoginStartResponse>, ApiError> {
    Ok(Json(LoginStartResponse {
        message: "Googleログインはフロントエンドから開始してください",
        auth_url: "",
    }))
}

pub async fn google_login_verify(
    State(state): State<AppState>,
    jar: CookieJar,
    Json(payload): Json<GoogleVerifyRequest>,
) -> Result<(CookieJar, Json<MessageResponse>), ApiError> {
    if payload.id_token.trim().is_empty() {
        return Err(ApiError::BadRequest("ログインに失敗しました".to_string()));
    }

    let expected_client_id = env::var("GOOGLE_CLIENT_ID")
        .map_err(|_| ApiError::InternalServerError)?;

    let token_info = reqwest::Client::new()
        .get("https://oauth2.googleapis.com/tokeninfo")
        .query(&[("id_token", payload.id_token.as_str())])
        .send()
        .await
        .map_err(|_| ApiError::InternalServerError)?;

    if !token_info.status().is_success() {
        return Err(ApiError::BadRequest("ログインに失敗しました".to_string()));
    }

    let token_info = token_info
        .json::<GoogleTokenInfoResponse>()
        .await
        .map_err(|_| ApiError::InternalServerError)?;

    if token_info.aud.as_deref() != Some(expected_client_id.as_str()) {
        return Err(ApiError::BadRequest("ログインに失敗しました".to_string()));
    }

    let google_sub = token_info
        .sub
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| ApiError::BadRequest("認証処理に失敗しました".to_string()))?;
    let email = token_info
        .email
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| ApiError::BadRequest("認証処理に失敗しました".to_string()))?;
    let user_name = token_info
        .name
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| email.clone());

    let user = user_repository::upsert_user_by_google_sub(
        &state.pool,
        &google_sub,
        &user_name,
        &email,
    )
    .await?;

    let jar = jar.add(session::create_session_cookie(user.user_id));
    Ok((
        jar,
        Json(MessageResponse {
            message: "ログインしました",
        }),
    ))
}

pub async fn google_login_callback(
    _state: State<AppState>,
    _jar: CookieJar,
    _query: Query<GoogleCallbackQuery>,
) -> Result<(CookieJar, Json<MessageResponse>), ApiError> {
    Err(ApiError::BadRequest("認証処理に失敗しました".to_string()))
}

pub async fn logout(jar: CookieJar) -> Result<(CookieJar, Json<MessageResponse>), ApiError> {
    let jar = jar.remove(session::clear_session_cookie());
    Ok((
        jar,
        Json(MessageResponse {
            message: "ログアウトしました",
        }),
    ))
}

pub async fn get_me(
    State(state): State<AppState>,
    jar: CookieJar,
) -> Result<Json<MeResponse>, ApiError> {
    let session_user = session::read_session_user(&jar).ok_or(ApiError::Unauthorized)?;
    let user = user_repository::find_user_by_id(&state.pool, session_user.user_id)
        .await?
        .ok_or_else(|| ApiError::NotFound("user not found".to_string()))?;

    Ok(Json(MeResponse {
        user_id: user.user_id.to_string(),
        google_sub: user.google_sub,
        user_name: user.user_name,
        email: user.email,
    }))
}

use crate::handlers::auth_handler;
use crate::AppState;
use axum::{
    routing::{get, post},
    Router,
};

pub fn routes() -> Router<AppState> {
    Router::new()
        .route("/api/auth/google/login", post(auth_handler::start_google_login))
        .route("/api/auth/google/verify", post(auth_handler::google_login_verify))
        .route(
            "/api/auth/google/callback",
            get(auth_handler::google_login_callback),
        )
        .route("/api/auth/logout", post(auth_handler::logout))
        .route("/api/users/me", get(auth_handler::get_me))
}

