"use client";

import { FormEvent, useEffect, useMemo, useState } from "react";

const apiBaseUrl = process.env.NEXT_PUBLIC_API_BASE_URL ?? "http://localhost:8080";

type Category = {
  category_id: string;
  category_name: string;
};

type Memo = {
  memo_id: string;
  title: string;
  content: string;
  category_id?: string;
  category_name: string;
  created_at: string;
  updated_at: string;
};

type MemoListResponse = {
  memos: Memo[];
};

type CategoryListResponse = {
  categories: Category[];
};

const formatDateTime = (value: string) => {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit"
  }).format(date);
};

export default function MemoListPage() {
  const [keywordInput, setKeywordInput] = useState("");
  const [keyword, setKeyword] = useState("");
  const [categoryId, setCategoryId] = useState("");
  const [categories, setCategories] = useState<Category[]>([]);
  const [memos, setMemos] = useState<Memo[]>([]);
  const [errorMessage, setErrorMessage] = useState("");
  const [categoryErrorMessage, setCategoryErrorMessage] = useState("");
  const [isReady, setIsReady] = useState(false);

  const queryString = useMemo(() => {
    const params = new URLSearchParams();
    if (keyword.trim()) {
      params.set("keyword", keyword.trim());
    }
    if (categoryId) {
      params.set("category_id", categoryId);
    }
    const raw = params.toString();
    return raw ? `?${raw}` : "";
  }, [keyword, categoryId]);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const initialKeyword = params.get("keyword") ?? "";
    const initialCategoryId = params.get("category_id") ?? "";

    setKeywordInput(initialKeyword);
    setKeyword(initialKeyword);
    setCategoryId(initialCategoryId);
    setIsReady(true);
  }, []);

  useEffect(() => {
    if (!isReady) {
      return;
    }
    const load = async () => {
      try {
        const response = await fetch(`${apiBaseUrl}/api/memos${queryString}`, {
          credentials: "include"
        });
        if (!response.ok) {
          let message = "メモ一覧の取得に失敗しました";
          try {
            const payload = (await response.json()) as { message?: string };
            message = payload.message ?? message;
          } catch {
            // no-op: use fallback message
          }
          throw new Error(message);
        }
        const payload = (await response.json()) as MemoListResponse;
        setMemos(payload.memos);
        setErrorMessage("");
      } catch (error) {
        setErrorMessage(error instanceof Error ? error.message : "通信に失敗しました");
        setMemos([]);
      }
    };
    void load();
  }, [isReady, queryString]);

  useEffect(() => {
    if (!isReady) {
      return;
    }
    const params = new URLSearchParams();
    if (keyword.trim()) {
      params.set("keyword", keyword.trim());
    }
    if (categoryId) {
      params.set("category_id", categoryId);
    }
    const raw = params.toString();
    const nextUrl = raw ? `${window.location.pathname}?${raw}` : window.location.pathname;
    window.history.replaceState(null, "", nextUrl);
  }, [categoryId, isReady, keyword]);

  useEffect(() => {
    const loadCategories = async () => {
      try {
        const response = await fetch(`${apiBaseUrl}/api/categories`, {
          credentials: "include"
        });
        if (!response.ok) {
          let message = "カテゴリ一覧の取得に失敗しました";
          try {
            const payload = (await response.json()) as { message?: string };
            message = payload.message ?? message;
          } catch {
            // no-op: use fallback message
          }
          throw new Error(message);
        }
        const payload = (await response.json()) as CategoryListResponse;
        setCategories(payload.categories);
        setCategoryErrorMessage("");
      } catch (error) {
        setCategoryErrorMessage(
          error instanceof Error ? error.message : "通信に失敗しました"
        );
        setCategories([]);
      }
    };
    void loadCategories();
  }, []);

  useEffect(() => {
    if (!categoryId || categories.length === 0) {
      return;
    }
    const exists = categories.some((category) => category.category_id === categoryId);
    if (!exists) {
      setCategoryId("");
    }
  }, [categories, categoryId]);

  const onSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setKeyword(keywordInput.trim());
  };

  return (
    <main className="page">
      <section className="card memo-list-card">
        <header className="memo-list-header">
          <h1>メモ一覧</h1>
          <div className="button-row">
            <a href="/memos/new" className="link-button">
              新規作成
            </a>
            <a href="/categories" className="outline-button">
              カテゴリ管理
            </a>
          </div>
        </header>

        <form onSubmit={onSubmit} className="form-block">
          <div className="memo-search-row">
            <input
              type="text"
              value={keywordInput}
              onChange={(event) => setKeywordInput(event.target.value)}
              placeholder="タイトル・本文を検索"
              aria-label="タイトル・本文を検索"
            />
            <button type="submit" className="google-button search-button">
              検索
            </button>
          </div>
          <select
            value={categoryId}
            onChange={(event) => setCategoryId(event.target.value)}
            aria-label="カテゴリで絞り込み"
            disabled={Boolean(categoryErrorMessage)}
            className="memo-category-filter"
          >
            <option value="">すべて</option>
            {categories.map((category) => (
              <option key={category.category_id} value={category.category_id}>
                {category.category_name}
              </option>
            ))}
          </select>
          {categoryErrorMessage && (
            <p className="error-text field-error">{categoryErrorMessage}</p>
          )}
        </form>

        {errorMessage && <p className="error-text list-status">{errorMessage}</p>}
        {!errorMessage && memos.length === 0 && (
          <p className="list-status">該当するメモがありません</p>
        )}

        {!errorMessage && memos.length > 0 && (
          <ul className="memo-list">
            {memos.map((memo) => (
              <li key={memo.memo_id} className="memo-list-item">
                <div className="memo-list-item-header">
                  <a href={`/memos/${memo.memo_id}`} className="memo-title-link">
                    {memo.title}
                  </a>
                  <div className="button-row memo-actions">
                    <a href={`/memos/${memo.memo_id}`} className="link-button">
                      詳細
                    </a>
                    <a href={`/memos/${memo.memo_id}/edit`} className="outline-button">
                      編集
                    </a>
                    <a href={`/memos/${memo.memo_id}/delete`} className="danger-link">
                      削除
                    </a>
                  </div>
                </div>

                <p className="memo-content-preview">{memo.content.trim() || "本文なし"}</p>

                <div className="memo-meta">
                  <span className="memo-category">{memo.category_name || "未分類"}</span>
                  <span>作成: {formatDateTime(memo.created_at)}</span>
                  <span>更新: {formatDateTime(memo.updated_at)}</span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}

:root {
  --bg: radial-gradient(circle at 20% 20%, #d7f7ff 0%, #eefcff 40%, #f9f7f3 100%);
  --text: #1f2d3d;
  --card: #ffffffd9;
  --line: #7cb3c7;
  --button: #1f6b83;
  --button-text: #f8fbff;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: var(--bg);
  color: var(--text);
  font-family: "Avenir Next", "Hiragino Kaku Gothic ProN", sans-serif;
}

.page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 24px;
}

.card {
  width: min(560px, 100%);
  border: 2px solid var(--line);
  border-radius: 16px;
  background: var(--card);
  padding: 32px;
  box-shadow: 0 16px 32px rgba(29, 78, 100, 0.15);
}

.card h1 {
  margin-top: 0;
  margin-bottom: 12px;
  font-size: 2rem;
}

.card p {
  margin-top: 0;
  margin-bottom: 24px;
}

.google-button {
  border: none;
  border-radius: 10px;
  padding: 12px 18px;
  background: var(--button);
  color: var(--button-text);
  font-size: 1rem;
  cursor: pointer;
}

.google-button:hover {
  filter: brightness(1.05);
}

.google-button:disabled {
  opacity: 0.7;
  cursor: wait;
}

.error-text {
  color: #b00020;
  margin-top: 12px;
  margin-bottom: 0;
}

.link-button {
  display: inline-block;
  margin-top: 12px;
  padding: 10px 14px;
  background: #f0f7fa;
  border-radius: 8px;
  border: 1px solid #7cb3c7;
  color: #17485a;
  text-decoration: none;
}

.form-block {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.form-block input {
  border: 1px solid #7cb3c7;
  border-radius: 8px;
  padding: 10px 12px;
  font-size: 1rem;
}

.form-block textarea,
.form-block select {
  border: 1px solid #7cb3c7;
  border-radius: 8px;
  padding: 10px 12px;
  font-size: 1rem;
  font-family: inherit;
}

.button-row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.outline-button {
  border: 1px solid #7cb3c7;
  border-radius: 10px;
  padding: 10px 16px;
  background: #ffffff;
  color: #1f2d3d;
  text-decoration: none;
  cursor: pointer;
}

.list {
  margin: 0;
  padding-left: 20px;
}

.list-item {
  margin-bottom: 10px;
}

.memo-list-card {
  width: min(860px, 100%);
}

.memo-list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
}

.memo-list-header h1 {
  margin-bottom: 0;
}

.memo-list-header .link-button,
.memo-list-header .outline-button,
.memo-actions .link-button,
.memo-actions .outline-button {
  margin-top: 0;
  padding: 8px 12px;
  font-size: 0.9rem;
}

.search-button {
  margin-top: 0;
}

.memo-search-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 10px;
  align-items: center;
}

.memo-category-filter {
  width: 33.333%;
}

.list-status {
  margin-top: 16px;
  margin-bottom: 0;
}

.memo-list {
  list-style: none;
  margin: 16px 0 0;
  padding: 0;
  display: grid;
  gap: 12px;
}

.memo-list-item {
  border: 1px solid #d5e8ef;
  border-radius: 12px;
  padding: 14px;
  background: #ffffff;
}

.memo-list-item-header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: flex-start;
}

.memo-title-link {
  color: #1b3a48;
  text-decoration: none;
  font-size: 1.05rem;
  font-weight: 700;
  line-height: 1.4;
}

.memo-title-link:hover {
  text-decoration: underline;
}

.memo-actions {
  justify-content: flex-end;
}

.memo-content-preview {
  margin: 10px 0;
  color: #334e5a;
  font-size: 0.95rem;
  line-height: 1.5;
  white-space: pre-wrap;
  overflow: hidden;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
}

.memo-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  font-size: 0.82rem;
  color: #5b7580;
}

.memo-category {
  display: inline-block;
  border: 1px solid #d0e1e8;
  border-radius: 999px;
  background: #f5fafc;
  color: #284958;
  padding: 2px 8px;
}

.danger-link {
  align-self: center;
  color: #7f2d2f;
  text-decoration: none;
  font-size: 0.85rem;
  padding: 4px 2px;
}

.danger-link:hover {
  text-decoration: underline;
}

@media (max-width: 720px) {
  .memo-search-row {
    grid-template-columns: 1fr;
  }

