"use client";

import { useState } from "react";

const apiBaseUrl = process.env.NEXT_PUBLIC_API_BASE_URL ?? "http://localhost:8080";

type Props = {
  className?: string;
};

export default function LogoutButton({ className = "outline-button" }: Props) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const onLogout = async () => {
    if (isSubmitting) {
      return;
    }

    setIsSubmitting(true);
    setErrorMessage("");

    try {
      const response = await fetch(`${apiBaseUrl}/api/auth/logout`, {
        method: "POST",
        credentials: "include"
      });

      if (!response.ok) {
        let message = "ログアウトに失敗しました";
        try {
          const payload = (await response.json()) as { message?: string };
          message = payload.message ?? message;
        } catch {
          // no-op: use fallback message
        }
        throw new Error(message);
      }

      window.location.href = "/";
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "通信に失敗しました");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="logout-group">
      <button
        type="button"
        className={className}
        onClick={onLogout}
        disabled={isSubmitting}
      >
        {isSubmitting ? "ログアウト中..." : "ログアウト"}
      </button>
      {errorMessage && <p className="error-text field-error">{errorMessage}</p>}
    </div>
  );
}

